"""PARSE 단계 — workflow_data JSON → NodeInfo + EdgeInfo."""

from __future__ import annotations

import logging
from typing import Any

from mantis.models.node import NodeInfo, PortInfo, EdgeInfo

logger = logging.getLogger(__name__)


def parse_workflow(workflow_data: dict[str, Any]) -> tuple[dict[str, NodeInfo], list[EdgeInfo]]:
    """workflow_data JSON을 내부 표현으로 파싱.

    Returns: (nodes dict, edges list)
    """
    raw_nodes = workflow_data.get("nodes", [])
    raw_edges = workflow_data.get("edges", [])

    nodes: dict[str, NodeInfo] = {}
    for raw in raw_nodes:
        node = _parse_node(raw)
        if node and not _is_disabled(raw):
            nodes[node.id] = node

    edges = [e for e in (_parse_edge(raw) for raw in raw_edges) if e is not None]

    # 비연결 노드 제거 (2개+ 노드일 때)
    if len(nodes) > 1:
        connected = set()
        for e in edges:
            connected.add(e.source_node)
            connected.add(e.target_node)
        disconnected = [nid for nid in nodes if nid not in connected]
        for nid in disconnected:
            logger.info("PARSE: 비연결 노드 제거 — %s", nid)
            del nodes[nid]

    # 비활성 노드를 참조하는 엣지 제거
    edges = [e for e in edges if e.source_node in nodes and e.target_node in nodes]

    return nodes, edges


def _parse_node(raw: dict) -> NodeInfo | None:
    node_id = raw.get("id", "")
    if not node_id:
        return None

    data = raw.get("data", {})
    position = raw.get("position", {})

    # 포트 파싱
    inputs = [_parse_port(p) for p in data.get("inputs", [])]
    outputs = [_parse_port(p) for p in data.get("outputs", [])]

    # 파라미터 파싱
    parameters = {}
    for param in data.get("parameters", []):
        name = param.get("name") or param.get("id", "")
        if name:
            parameters[name] = param.get("value", param.get("default", ""))

    return NodeInfo(
        id=node_id,
        function_id=data.get("functionId", "default"),
        category_id=data.get("categoryId", ""),
        name=data.get("nodeName", node_id),
        parameters=parameters,
        inputs=inputs,
        outputs=outputs,
        bypass=data.get("bypass", False),
        position=(position.get("y", 0), position.get("x", 0)),
    )


def _parse_port(raw: dict) -> PortInfo:
    return PortInfo(
        id=raw.get("id", raw.get("name", "")),
        type=raw.get("type", "STR"),
        multi=raw.get("multi", False),
        required=raw.get("required", True),
        dependency=raw.get("dependency"),
        dependency_value=raw.get("dependencyValue"),
    )


def _parse_edge(raw: dict) -> EdgeInfo | None:
    source = raw.get("source", {})
    target = raw.get("target", {})

    # xgen 형식: {source: {nodeId, portId}} 또는 flat {source: "nodeId", sourceHandle: "portId"}
    if isinstance(source, dict):
        src_node = source.get("nodeId", "")
        src_port = source.get("portId", "output")
    else:
        src_node = str(source)
        src_port = raw.get("sourceHandle", "output")

    if isinstance(target, dict):
        tgt_node = target.get("nodeId", "")
        tgt_port = target.get("portId", "input")
    else:
        tgt_node = str(target)
        tgt_port = raw.get("targetHandle", "input")

    if not src_node or not tgt_node:
        return None

    return EdgeInfo(
        source_node=src_node,
        source_port=src_port,
        target_node=tgt_node,
        target_port=tgt_port,
    )


def _is_disabled(raw: dict) -> bool:
    data = raw.get("data", {})
    return data.get("disable", False) or data.get("disabled", False)
